<template>
  <div class="w-full h-full flex">
    <div class="w-3/4 h-full self-center mx-auto flex flex-col">
      <!-- 导航栏 -->
      <div class="w-full mx-auto mt-10 rounded border-b-4 shadow-xl rounded-xl">
        <ul class="w-full inline-flex space-x-2 px-1 pt-2 overflow-x-scroll">
          <li
            v-for="(item, index) in submode"
            :key="submode + index"
            class="cursor-pointer whitespace-nowrap flex-nowrap px-4 py-2 font-semibold text-gray-800 rounded-t opacity-50"
            :class="[
              current_type_id == index
                ? 'border-blue-400 border-b-4 -mb-px opacity-100'
                : '',
            ]"
            @click.stop="
              mode_current = item;
              current_type_id = index;
            "
          >
            {{ item }}
          </li>
        </ul>
      </div>

      <!-- 内容框 -->
      <div class="h-5/6 w-full mt-10 mx-auto border-t-2 shadow-xl rounded-xl">
        <div class="flex w-full h-full relative">
          <div
            id="content_table"
            class="flex-grow overflow-y-auto bg-gray-100"
            style="scroll-behavior: smooth"
          >
            <div
              class="
                relative
                w-full
                p-3
                mb-3
                grid gap-8
                bg-white
                grid-cols-2 
                lg:grid-cols-4
              "
              v-for="(menu, menu_i) in content"
              :key="'menu' + menu_i"
            >
              <div
                class="
                  w-full
                  p-3
                  bg-white
                  flex-none
                  border-2
                  shadow-xl
                  cursor-pointer
                "
                v-for="(item, item_i) in menu.data"
                :key="'item' + item_i"
                @click.stop="openTab(item['path'])"
              >
                <div class="flex flex-nowrap w-full h-full">
                  <img class="w-6 h-6 flex-none" :src="item['icon']" />
                  <div class="ml-1 flex-grow text-center">
                    {{ item["name"] }}
                  </div>
                </div>
              </div>
            </div>
          </div>
          <div class="absolute inset-y-0 -right-36 w-36">
            <!-- 时间线，加在内容框的左边 -->
            <com-timeline :timeline="timeline" :cb="switch_content" />
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import ComTimeline from "@/components/Timeline.vue";

const MENU_DATA = require("@/configs/compass.js").MENU_DATA;

export default {
  name: "MenuPage",
  components: {
    ComTimeline,
  },
  data() {
    return {
      // current: "编程语言",
      current_type_id: 0, // 默认第一个
      mode_current: undefined,
    };
  },
  computed: {
    current() {
      return this.mode_current || this.submode[0];
    },
    submode() {
      let res = [];
      for (let i of MENU_DATA) {
        res.push(i["meta"]);
      }
      return res;
    },
    timeline() {
      // 当前目录下的timeline
      for (let item of MENU_DATA) {
        if (item["meta"] === this.current) {
          let res = [];
          for (let sub of item["content"]) {
            res.push(sub["tag"]);
          }
          return res;
        }
      }
      return [];
    },
    content() {
      for (let item of MENU_DATA) {
        if (item["meta"] === this.current) {
          return item["content"];
        }
      }
      return [];
    },
  },

  mounted() {
    // this.$nextTick(() => {
    //   createPopper(
    //     document.querySelector("#content"),
    //     document.querySelector("#timeline"),
    //     {
    //       placement: "right",
    //     }
    //   );
    // });
  },

  methods: {
    openTab(url) {
      this.$store.dispatch("OpenTab", url);
    },
    switch_mode(mode) {
      this.mode_current = mode;
    },
    switch_content(index) {
      // 获取ref=content_table中第index个元素，获取content_table的clientY，将目标元素往上移动
      let content_table = document.querySelector("#content_table");
      let target = document.querySelector(
        `#content_table > div:nth-child(${index + 1})`
      );
      // let content_target = content_
      // console.log(content_table.getBoundingClientRect().top, target.getBoundingClientRect().top);
      // content_table.clientTop
      content_table.scrollTop +=
        target.getBoundingClientRect().top -
        content_table.getBoundingClientRect().top -
        12;
    },
  },
};
</script>